```php
<?php

// Assuming you have a PDO connection established and a query executed
// For example:
$pdo = new PDO('mysql:host=localhost;dbname=your_database', 'your_user', 'your_password');
$stmt = $pdo->query("SELECT column1, column2, column3 FROM your_table");


// Method 1:  Looping with fetch(PDO::FETCH_ASSOC)
$results = []; // Initialize an array to store all results

while ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {
    $results[] = $row; // Add each row (as an associative array) to the $results array
}

// Now $results is a multi-dimensional array. Each element of $results
// is a row from your database, and each row is an associative array
// with column names as keys.

// Example of accessing data:
foreach ($results as $row) {
    echo "Column1: " . $row['column1'] . ", Column2: " . $row['column2'] . ", Column3: " . $row['column3'] . "<br>";
}



// Method 2:  fetchALL(PDO::FETCH_ASSOC) - More concise
// This retrieves all rows at once into a single array.  Use with caution
// if you expect a very large result set, as it can consume a lot of memory.
$results = $stmt->fetchAll(PDO::FETCH_ASSOC);

// Now $results directly contains the array of associative arrays.
// Example of accessing data:
foreach ($results as $row) {
    echo "Column1: " . $row['column1'] . ", Column2: " . $row['column2'] . ", Column3: " . $row['column3'] . "<br>";
}


//Important:  Always close the statement and connection when finished.
